+    /// Haven't tried calling the service yet.
+    #[default]
+    Untried,
+    /// At least one successful contact — keep using live calls.
+    Available,
+    /// Connection failure observed — fall back to synthetic mocks for the
+    /// remainder of this exploration run.
+    Unavailable,
+}
