+    let already_mocked: std::collections::HashSet<&str> = existing_mocks
+        .iter()
+        .map(|m| m.symbol.as_str())
+        .collect();
+
+    let mut result = Vec::new();
+
+    for dep in deps {
+        if already_mocked.contains(dep.symbol.as_str()) {
+            continue;
+        }
